import type { HTMLAttributes } from "astro/types"
import type {
  Align as ComboboxAlign,
  Side as ComboboxSide,
} from "@data-slot/combobox"

import { cn } from "@/lib/utils"

type Props = HTMLAttributes<"div"> & {
  side?: ComboboxSide
  align?: ComboboxAlign
  sideOffset?: number
  alignOffset?: number
  avoidCollisions?: boolean
  collisionPadding?: number
}

const {
  class: className,
  hidden = true,
  side,
  align,
  sideOffset,
  alignOffset,
  avoidCollisions,
  collisionPadding,
  ...props
} = Astro.props
---

<div data-slot="combobox-portal">
  <div
    data-slot="combobox-positioner"
    data-side={side}
    data-align={align}
    data-side-offset={sideOffset}
    data-align-offset={alignOffset}
    data-avoid-collisions={avoidCollisions}
    data-collision-padding={collisionPadding}
    class="isolate z-50"
  >
    <div
      data-slot="combobox-content"
      data-side={side}
      data-align={align}
      data-side-offset={sideOffset}
      data-align-offset={alignOffset}
      data-avoid-collisions={avoidCollisions}
      data-collision-padding={collisionPadding}
      hidden={hidden}
      class={cn(
        "group/combobox-content bg-popover text-popover-foreground ring-foreground/10 data-[side=bottom]:slide-in-from-top-2 data-[side=inline-end]:slide-in-from-left-2 data-[side=inline-start]:slide-in-from-right-2 data-[side=left]:slide-in-from-right-2 data-[side=right]:slide-in-from-left-2 data-[side=top]:slide-in-from-bottom-2 data-open:animate-in data-open:fade-in-0 data-open:zoom-in-95 data-closed:animate-out data-closed:fade-out-0 data-closed:zoom-out-95 *:data-[slot=input-group]:border-input/30 *:data-[slot=input-group]:bg-input/30 relative z-50 max-h-(--available-height) w-(--anchor-width) max-w-(--available-width) min-w-[calc(var(--anchor-width)+--spacing(7))] origin-(--transform-origin) overflow-hidden rounded-md shadow-md ring-1 duration-100 *:data-[slot=input-group]:m-1 *:data-[slot=input-group]:mb-0 *:data-[slot=input-group]:h-8 *:data-[slot=input-group]:shadow-none",
        className
      )}
      {...props}
    >
      <slot />
    </div>
  </div>
</div>

---
import type { HTMLAttributes } from "astro/types"

import { cn } from "@/lib/utils"
import { Icon } from "@/components/ui/icon"
import InputGroupAddon from "@/components/ui/input-group/input-group-addon.astro"
import InputGroupInput from "@/components/ui/input-group/input-group-input.astro"
import InputGroup from "@/components/ui/input-group/input-group.astro"

import ComboboxTrigger from "./combobox-trigger.astro"

type Props = HTMLAttributes<"input"> & {
  showTrigger?: boolean
  showClear?: boolean
}

const {
  class: className,
  type = "text",
  disabled = false,
  showTrigger = true,
  showClear = false,
  ...props
} = Astro.props
---

<InputGroup class={cn("w-auto", className)}>
  <InputGroupInput
    type={type}
    data-slot="combobox-input"
    disabled={disabled}
    {...props}
  />
  <InputGroupAddon align="inline-end">
    {
      showTrigger && (
        <ComboboxTrigger
          class="group-has-data-[slot=combobox-clear]/input-group:hidden data-pressed:bg-transparent"
          disabled={disabled}
        />
      )
    }
    {
      showClear && (
        <button
          type="button"
          data-slot="combobox-clear"
          class="inline-flex size-6 shrink-0 items-center justify-center rounded-[calc(var(--radius)-5px)] p-0 text-sm shadow-none outline-none disabled:pointer-events-none disabled:opacity-50 [&_svg]:pointer-events-none [&_svg]:shrink-0 [&_svg:not([class*='size-'])]:size-4"
          disabled={disabled}
        >
          <Icon name="x" class="pointer-events-none" />
        </button>
      )
    }
  </InputGroupAddon>
  <slot />
</InputGroup>

